public String chompBalanced(char open, char close) {
    int start = -1;
    int end = -1;
    int depth = 0;
    char last = 0;
    boolean quoteOpen = false;
    final char SINGLE_QUOTE = '\'';
    final char DOUBLE_QUOTE = '"';

    do {
        if (isEmpty()) break;
        Character c = consume();
        if (last == 0 || last != ESC) {
            if ((c == open && !quoteOpen) || (c == close && !quoteOpen)) {
                depth += (c == open) ? 1 : -1;
                if (depth > 0 && start == -1)
                    start = pos;
            } else if ((c == SINGLE_QUOTE || c == DOUBLE_QUOTE) && last != ESC) {
                quoteOpen = !quoteOpen;
            }
        }

        if (depth > 0 && last != 0)
            end = pos; // don't include the outer match pair in the return
        last = c;
    } while (depth > 0);
    return (end >= 0) ? queue.substring(start, end) : "";
}
